import{_ as a,o as s,c as n,b as i,w as c,d as e,e as d,a as o,r as l}from"./app.1fbcae6f.js";const p="/vite-press-blog/assets/structure-computer-networks1.379ce060.png",h="/vite-press-blog/assets/structure-computer-networks2.619e2b31.png",u="/vite-press-blog/assets/structure-computer-networks3.527e4b4d.png",_="/vite-press-blog/assets/structure-computer-networks4.b502b767.png",m="/vite-press-blog/assets/structure-computer-networks5.08fe8aac.png",g="/vite-press-blog/assets/structure-computer-networks6.38c87dd7.png",b="/vite-press-blog/assets/structure-computer-networks7.23dfcfb4.png",P="/vite-press-blog/assets/structure-computer-networks8.2263fea7.png",D=JSON.parse('{"title":"计算机网络分层结构","description":"","frontmatter":{"createTime":"2022/10/26","tag":"计算机"},"headers":[{"level":2,"title":"一、几种分层结构","slug":"一、几种分层结构","link":"#一、几种分层结构","children":[]},{"level":2,"title":"二、OSI参考模型","slug":"二、osi参考模型","link":"#二、osi参考模型","children":[{"level":3,"title":"1. 应用层","slug":"_1-应用层","link":"#_1-应用层","children":[]},{"level":3,"title":"2. 表示层","slug":"_2-表示层","link":"#_2-表示层","children":[]},{"level":3,"title":"3. 会话层","slug":"_3-会话层","link":"#_3-会话层","children":[]},{"level":3,"title":"4. 传输层","slug":"_4-传输层","link":"#_4-传输层","children":[]},{"level":3,"title":"5. 网络层","slug":"_5-网络层","link":"#_5-网络层","children":[]},{"level":3,"title":"6. 数据链路层","slug":"_6-数据链路层","link":"#_6-数据链路层","children":[]},{"level":3,"title":"7. 物理层","slug":"_7-物理层","link":"#_7-物理层","children":[]}]},{"level":2,"title":"三、TCP/IP模型","slug":"三、tcp-ip模型","link":"#三、tcp-ip模型","children":[]},{"level":2,"title":"四、5层参考模型","slug":"四、5层参考模型","link":"#四、5层参考模型","children":[]}],"relativePath":"basic-quality/structure-computer-networks/index.md","lastUpdated":1667281923000}'),f={name:"basic-quality/structure-computer-networks/index.md"},k=e("h1",{id:"计算机网络分层结构",tabindex:"-1"},[d("计算机网络分层结构 "),e("a",{class:"header-anchor",href:"#计算机网络分层结构","aria-hidden":"true"},"#")],-1),v=o('<h2 id="一、几种分层结构" tabindex="-1">一、几种分层结构 <a class="header-anchor" href="#一、几种分层结构" aria-hidden="true">#</a></h2><p><img src="'+p+'" alt="图片"></p><h2 id="二、osi参考模型" tabindex="-1">二、OSI参考模型 <a class="header-anchor" href="#二、osi参考模型" aria-hidden="true">#</a></h2><ul><li><p>目的：支持异构网络系统的互联互通（制定一个标准）</p></li><li><p>7层结构 <img src="'+h+'" alt="图片"></p></li><li><p>巧记：物链网输会示用（一个叫淑慧的人试用物联网）</p></li><li><p>通信子网：专注于数据传输通信（邮寄）</p></li><li><p>资源子网：专注于数据处理（包装） <img src="'+u+'" alt="图片"></p></li></ul><h3 id="_1-应用层" tabindex="-1">1. 应用层 <a class="header-anchor" href="#_1-应用层" aria-hidden="true">#</a></h3><ul><li>用户与网络的界面</li><li>所有能和用户交互产生网络流量的程序</li><li>典型应用层服务：文件传输（FTP）、电子邮件（SMTP）、万维网（HTTP）</li></ul><h3 id="_2-表示层" tabindex="-1">2. 表示层 <a class="header-anchor" href="#_2-表示层" aria-hidden="true">#</a></h3><ul><li>处理两种通信系统中交换信息的表示方式</li><li>比如说，数据格式变换（编码格式之间的转换，使得不同主机之间即使在不同的编码格式上，也能消息互通）</li><li>数据加密解密（password传输）</li><li>数据压缩和恢复（发送端压缩，接受端解压缩）</li><li>在TCP/IP中被纳入到应用层中</li></ul><h3 id="_3-会话层" tabindex="-1">3. 会话层 <a class="header-anchor" href="#_3-会话层" aria-hidden="true">#</a></h3><ul><li>向表示层实体/用户进程提供建立连接并在连接上有序地传输数据</li><li>建立连接（建立一个session）</li><li>建立同步（SYN）</li><li>功能一：建立、管理、终止会话</li><li>功能二：使用校验点可使在通信失效和恢复之后，从校验点继续恢复通信，无需从头开始。适用于传输大文件。</li><li>ADSP、ASP</li></ul><h3 id="_4-传输层" tabindex="-1">4. 传输层 <a class="header-anchor" href="#_4-传输层" aria-hidden="true">#</a></h3><ul><li>负责主机中两个进程的通信，即端对端的通信。传输单位是报文段或用户数据报。（因为是端口号之间的通信，因此是端对端）</li><li>下面的几层，是计算机与计算机之间的通信，因此是点对点的通信。</li><li>功能一：可靠传输与不可靠传输。（即存不存在确认机制）</li><li>功能二：差错控制。对发生的差错，如何控制。</li><li>功能三：流量控制。传输速度匹配控制，接收方根据自己的处理速度，控制发送方速度。</li><li>功能四：复用分用。复用，即多个进程同时使用下面传输层的服务（两个进程的消息携带着端口号一起发送给传输层）；分用，即运输层将接收到的信息分发到不同的进程。</li><li>（可差留用，绝不认输）</li><li>主要协议：TCP、UDP</li></ul><h3 id="_5-网络层" tabindex="-1">5. 网络层 <a class="header-anchor" href="#_5-网络层" aria-hidden="true">#</a></h3><ul><li>主要任务：把分组从源端传送到目的端，为分组交换网上的不同主机提供通信服务。（数据过大时进行切割）（实现网际互联）</li><li>传输单位是数据包</li><li>功能一：路由选择。通过路由选择算法，选择合适的路由器路径进行传输。</li><li>功能二：流量控制。限制发送方速度。</li><li>功能三：差错控制。比如说，奇偶校验码。</li><li>功能四：拥塞控制。若所有节点都来不及接受分组了，而要丢弃大量分组，这时候就处于网络拥塞状态。</li><li>主要协议：IP、IPX、ICMP、IGMP、ARP、RARP、OSPF</li></ul><h3 id="_6-数据链路层" tabindex="-1">6. 数据链路层 <a class="header-anchor" href="#_6-数据链路层" aria-hidden="true">#</a></h3><ul><li><p>把网络层传下来的数据包组装成帧。</p></li><li><p>传输单位是帧。</p></li><li><p>功能一：成帧。（定义帧的开始和结束）</p></li><li><p>功能二：差错控制。帧错+位错。</p></li><li><p>功能三：流量控制</p></li><li><p>功能四：访问（接入）控制。控制对信道的访问。控制哪台主机可以占用信道。 <img src="'+_+'" alt="图片"></p></li><li><p>主要协议：SDLC、HDLC、PPP、STP</p></li></ul><h3 id="_7-物理层" tabindex="-1">7. 物理层 <a class="header-anchor" href="#_7-物理层" aria-hidden="true">#</a></h3><ul><li>将比特流转换为电信号进行传输。</li><li>物理传输单位是比特。</li><li>透明传输：不管给什么比特流，都转发。</li><li>功能一：定义接口特性。（物理上，接口怎么接）</li><li>功能二：定义传输模式，单工、半双工、双攻</li><li>功能三：定义传输速率</li><li>功能四：比特同步</li><li>功能五：比特编码</li><li>常见协议：RJ45、802.3</li></ul><h2 id="三、tcp-ip模型" tabindex="-1">三、TCP/IP模型 <a class="header-anchor" href="#三、tcp-ip模型" aria-hidden="true">#</a></h2><p><img src="'+m+'" alt="图片"><img src="'+g+'" alt="图片"></p><h2 id="四、5层参考模型" tabindex="-1">四、5层参考模型 <a class="header-anchor" href="#四、5层参考模型" aria-hidden="true">#</a></h2><p><img src="'+b+'" alt="图片"></p><p><img src="'+P+'" alt="图片"></p>',23);function x(T,S,w,C,I,A){const t=l("ArticleMetadata"),r=l("ClientOnly");return s(),n("div",null,[k,i(r,null,{default:c(()=>[i(t)]),_:1}),v])}const O=a(f,[["render",x]]);export{D as __pageData,O as default};
